        // --- Option 1: Mouse + base ---
        float sensitivity = mix(0.2, 2.0, uFrequency);  // Frequency = força do mouse
        float baseH = (uAmount - 0.5) * 1.6;             // base fixa
        float baseV = (uAmplitude - 0.5) * 1.6;

        // Mouse adiciona sobre a base
        float mouseH = (uMousePos.x - 0.5) * sensitivity;
        float mouseV = (uMousePos.y - 0.5) * sensitivity;

        hTilt = baseH + mouseH;
        vTilt = baseV + mouseV;

        // Clamp para não flipar
