        float rangeH = (uAmount - 0.5) * 1.2;       // Amount = amplitude H da animação
        float rangeV = (uAmplitude - 0.5) * 1.2;     // Amplitude = amplitude V

        hTilt = sin(uTime * speed) * rangeH;
        vTilt = cos(uTime * speed * 0.7) * rangeV;

        edgeSoft = 0.02;

