    vec2 warpedUV = marks_perspective(uv, hTilt, vTilt, zoom, offset, angle);

    // --- Máscara ---
    float mask = marks_rectMask(warpedUV, edgeSoft);

    // --- Amostragem ---
    vec2 sampleUV = clamp(warpedUV, 0.0, 1.0);
    vec4 tex = texture(uTexture, sampleUV);

    fragColor = vec4(tex.rgb, tex.a * mask);
